func depsSatisfied(b Bead, statusMap map[string]string) bool {
	for _, depID := range b.DepIDs() {
		if statusMap[depID] != StatusClosed {
			return false
		}
	}
	return true
}

func isOrdinaryEpicContainer(b Bead, childCount int) bool {
	issueType := strings.ToLower(strings.TrimSpace(b.IssueType))
	title := strings.ToLower(strings.TrimSpace(b.Title))
	return issueType == "epic" || strings.HasPrefix(title, "epic:") || (childCount > 0 && strings.HasPrefix(title, "epic "))
}

func sortBeadsForQueue(beads []Bead) {
	sort.SliceStable(beads, func(i, j int) bool {
		if beads[i].Priority != beads[j].Priority {
			return beads[i].Priority < beads[j].Priority
		}
		ir, iok := parseQueueRank(beads[i].Extra["queue-rank"])
		jr, jok := parseQueueRank(beads[j].Extra["queue-rank"])
		if iok != jok {
			return iok
		}
		if iok && jok && ir != jr {
			return ir < jr
		}
		if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
			return beads[i].CreatedAt.Before(beads[j].CreatedAt)
		}
		return beads[i].ID < beads[j].ID
	})
}

func parseQueueRank(raw any) (int, bool) {
	switch v := raw.(type) {
	case int:
		return v, true
	case int8:
		return int(v), true
	case int16:
		return int(v), true
	case int32:
		return int(v), true
	case int64:
		return int(v), true
	case uint:
		return int(v), true
	case uint8:
		return int(v), true
	case uint16:
		return int(v), true
	case uint32:
		return int(v), true
	case uint64:
		return int(v), true
	case float32:
		return int(v), v == float32(int(v))
	case float64:
		return int(v), v == float64(int(v))
	case json.Number:
		if n, err := v.Int64(); err == nil {
			return int(n), true
		}
		if f, err := v.Float64(); err == nil {
			return int(f), f == float64(int(f))
		}
	case string:
		if n, err := strconv.Atoi(strings.TrimSpace(v)); err == nil {
			return n, true
		}
	}
	return 0, false
}

// Status returns aggregate counts.
func (s *Store) Status() (*StatusCounts, error) {
	beads, err := s.ReadAll()

package bead

import (
	"fmt"
	"strings"
	"time"
)

// Bead represents a portable work item with metadata.
// The schema matches bd/br JSONL format for interchange compatibility.
// Unknown fields from external sources are preserved in Extra.
type Bead struct {
	ID        string    `json:"id"`
	Title     string    `json:"title"`
	Status    string    `json:"status"`
	Priority  int       `json:"priority"`
	IssueType string    `json:"issue_type"`
	Owner     string    `json:"owner,omitempty"`
	CreatedAt time.Time `json:"created_at"`
	CreatedBy string    `json:"created_by,omitempty"`
	UpdatedAt time.Time `json:"updated_at"`

	// Optional fields (bd-compatible)
	Labels      []string `json:"labels,omitempty"`
	Parent      string   `json:"parent,omitempty"`
	Description string   `json:"description,omitempty"`
	Acceptance  string   `json:"acceptance,omitempty"`
	Notes       string   `json:"notes,omitempty"`

	// Dependencies use bd-compatible format
	Dependencies []Dependency `json:"dependencies,omitempty"`

	// Extra holds unknown fields for round-trip preservation.
	// Workflow-specific fields (e.g. HELIX spec-id, execution-eligible)
	// are stored here and written back on save.
	Extra map[string]any `json:"-"`
}

// Dependency represents a link between two beads (bd-compatible format).
type Dependency struct {
	IssueID     string `json:"issue_id"`
	DependsOnID string `json:"depends_on_id"`
	Type        string `json:"type"` // "blocks", "related", etc.
	CreatedAt   string `json:"created_at,omitempty"`
	CreatedBy   string `json:"created_by,omitempty"`
	Metadata    string `json:"metadata,omitempty"`
}

// BeadEvent records append-only execution evidence.
type BeadEvent struct {
	Kind      string    `json:"kind"`
	Summary   string    `json:"summary,omitempty"`
	Body      string    `json:"body,omitempty"`
	Actor     string    `json:"actor,omitempty"`
	CreatedAt time.Time `json:"created_at"`
	Source    string    `json:"source,omitempty"`
}

// Status constants
const (
	StatusOpen       = "open"
	StatusInProgress = "in_progress"
	StatusClosed     = "closed"
	// StatusBlocked marks a bead that is not eligible for agent dispatch —
	// either decomposed into child beads by the triage gate or parked for
	// human intervention after a triage-overflow event. Blocked beads are
	// excluded from ReadyExecution and will not be auto-dispatched.
	StatusBlocked = "blocked"
	// StatusProposed marks an operator-prompt bead awaiting approval. It is
	// excluded from execute-loop drain until transitioned to open via the
	// approval flow, or to cancelled when the operator declines it.
	StatusProposed = "proposed"
	// StatusCancelled marks a bead that was rejected before any execution
	// took place (e.g. an operator-prompt bead the user chose not to run).
	StatusCancelled = "cancelled"
)

// CanonicalStatuses is the single source of truth for the persisted bead
// status enumeration. It mirrors the bd/br canonical set documented in
// TD-031 §2 and the JSON Schema enum at
// cli/internal/bead/schema/bead-record.schema.json. The CI guard tests in
// sync_test.go assert that schema, TD doc, and Go source agree with this
// list; adding or removing a value here without updating the schema and TD
// will fail CI.
var CanonicalStatuses = []string{
	StatusOpen,
	StatusInProgress,
	StatusClosed,
	StatusBlocked,
	StatusProposed,
	StatusCancelled,
}

// IsCanonicalStatus reports whether s is one of the persisted bead statuses
// in CanonicalStatuses.
func IsCanonicalStatus(s string) bool {
	for _, c := range CanonicalStatuses {
		if c == s {
			return true
		}
	}
	return false
}

// IssueType constants
const (
	// IssueTypeOperatorPrompt is the bead type used for operator-submitted
	// prompts that the execute-loop runs as instructions.
	IssueTypeOperatorPrompt = "operator-prompt"
)

// Default labels and other defaults for operator-prompt beads.
const (
	OperatorPromptLabelKind   = "kind:operator-prompt"
	OperatorPromptLabelSource = "source:web-ui"
	// OperatorPromptDefaultAcceptance is the auto-AC stub used when an
	// operator submits a prompt without explicit acceptance criteria. The
	// structural AC verifier is skipped for operator-prompt beads, so this
	// stub stands as a human-readable contract only.
	OperatorPromptDefaultAcceptance = "Agent must produce a diff or no_changes rationale; the prompt body is the contract."
)

// OperatorPromptMutationGuard enforces the no-self-mutation rule from
// Story 15: an operator-prompt bead's execution may not create, edit, or
// close another operator-prompt bead. The guard returns nil when the
// mutation is allowed and a non-nil error when it must be rejected.
//
// actorIssueType is the issue_type of the bead currently being executed
// (empty when no operator-prompt context is active). targetIssueType is
// the issue_type of the bead about to be mutated.
//
// Allow/deny matrix:
//
//	actor=""               , target=*                → allow
//	actor="task"           , target=*                → allow
//	actor="operator-prompt", target!="operator-prompt" → allow
//	actor="operator-prompt", target=="operator-prompt" → deny
func OperatorPromptMutationGuard(actorIssueType, targetIssueType string) error {
	if actorIssueType != IssueTypeOperatorPrompt {
		return nil
	}
	if targetIssueType != IssueTypeOperatorPrompt {
		return nil
	}
	return fmt.Errorf("bead: operator-prompt bead may not mutate another operator-prompt bead")
}

// NewOperatorPromptBead constructs a fresh operator-prompt bead from a raw
// prompt string, applying the Story 15 template defaults: title is the first
// non-empty line of the prompt, full prompt body is preserved verbatim in the
// description, default labels are kind:operator-prompt + source:web-ui, the
// status starts in `proposed` (approval flow), priority defaults to the
// caller-supplied tier (clamped to MinPriority..MaxPriority), and the
// acceptance field carries the auto-AC stub.
//
// The returned bead is not persisted; callers feed it to Store.Create which
// will assign the ID and CreatedAt/UpdatedAt timestamps.
func NewOperatorPromptBead(prompt string, defaultTier int) *Bead {
	body := strings.TrimSpace(prompt)
	title := body
	if i := strings.IndexByte(body, '\n'); i >= 0 {
		title = strings.TrimSpace(body[:i])
	}
	if title == "" {
		title = "(empty operator prompt)"
	}
	tier := defaultTier
	if tier < MinPriority {
		tier = MinPriority
	}
	if tier > MaxPriority {
		tier = MaxPriority
	}
	return &Bead{
		Title:       title,
		IssueType:   IssueTypeOperatorPrompt,
		Status:      StatusProposed,
		Priority:    tier,
		Labels:      []string{OperatorPromptLabelKind, OperatorPromptLabelSource},
		Description: body,
		Acceptance:  OperatorPromptDefaultAcceptance,
	}
}

// Default values
const (
	DefaultType     = "task"
	DefaultStatus   = StatusOpen
	DefaultPriority = 2
	DefaultPrefix   = "bx" // used only when repo name detection fails
	MinPriority     = 0
	MaxPriority     = 4
)

// StatusCounts holds aggregate counts for a bead store.
type StatusCounts struct {
	Open    int `json:"open"`
	Closed  int `json:"closed"`
	Blocked int `json:"blocked"`
	Ready   int `json:"ready"`
	Total   int `json:"total"`
}

// Blocker kinds surfaced through BlockedAll. These strings are part of the
// external DDx contract (HELIX reads them to decide how to handle a blocker).
const (
	BlockerKindDependency         = "dependency"
	BlockerKindBlockedStatus      = "blocked-status"
	BlockerKindRetryCooldown      = "retry-cooldown"
	BlockerKindNeedsInvestigation = "needs-investigation"
	BlockerKindNotEligible        = "not-execution-eligible"
	BlockerKindSuperseded         = "superseded"
	BlockerKindEpicOnly           = "epic-only"
)

// Blocker describes why an open bead is currently not runnable. Either
// unclosed dependencies exist, or an execute-loop cooldown has parked the
// bead until NextEligibleAt.
type Blocker struct {
	Kind           string   `json:"kind"`

	}
	return f.WorkingDir
}

func (f *CommandFactory) beadStore() *bead.Store {
	workspaceRoot := f.beadWorkspaceRoot()
	if workspaceRoot == "" {
		return bead.NewStore("")
	}
	return bead.NewStore(filepath.Join(workspaceRoot, ".ddx"))
}

func (f *CommandFactory) newBeadInitCommand() *cobra.Command {
	return &cobra.Command{
		Use:   "init",
		Short: "Initialize bead storage",
		Args:  cobra.NoArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			s := f.beadStore()
			if err := s.Init(); err != nil {
				return err
			}
			fmt.Fprintf(cmd.OutOrStdout(), "Initialized bead storage at %s\n", s.File)

			// Auto-migrate from .helix/issues.jsonl if present
			n, migrated, err := s.MigrateFromHelix()
			if err != nil {
				fmt.Fprintf(cmd.ErrOrStderr(), "Warning: migration from .helix/issues.jsonl failed: %v\n", err)
			} else if migrated {
				fmt.Fprintf(cmd.OutOrStdout(), "Migrated %d beads from .helix/issues.jsonl\n", n)
			}
			return nil
		},
	}
}

func (f *CommandFactory) newBeadCreateCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "create <title>",
		Short: "Create a new bead",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			s := f.beadStore()
			b := &bead.Bead{Title: args[0]}

			if v, _ := cmd.Flags().GetString("type"); v != "" {
				b.IssueType = v
			}
			if v, _ := cmd.Flags().GetInt("priority"); cmd.Flags().Changed("priority") {
				b.Priority = v
			}
			if v, _ := cmd.Flags().GetString("labels"); v != "" {
				b.Labels = strings.Split(v, ",")
			}
			if v, _ := cmd.Flags().GetString("acceptance"); v != "" {
				b.Acceptance = v
			}
			if v, _ := cmd.Flags().GetString("description"); v != "" {
				b.Description = v
			}
			if v, _ := cmd.Flags().GetString("parent"); v != "" {
				b.Parent = v
			}
			if setFlags, _ := cmd.Flags().GetStringArray("set"); len(setFlags) > 0 {
				if b.Extra == nil {
					b.Extra = make(map[string]any)
				}
				for _, kv := range setFlags {
					k, v, ok := strings.Cut(kv, "=")
					if !ok {
						return fmt.Errorf("--set requires key=value format, got: %s", kv)
					}
					switch v {
					case "true":
						b.Extra[k] = true
					case "false":
						b.Extra[k] = false
					default:
						b.Extra[k] = v
					}
				}
			}

			if err := s.Create(b); err != nil {
				return err
			}
			f.beadAutoCommit("create " + b.ID)
			fmt.Fprintf(cmd.OutOrStdout(), "%s\n", b.ID)
			return nil
		},
	}

	cmd.Flags().String("type", "", "Bead type (task, bug, epic, chore)")
	cmd.Flags().Int("priority", 2, "Priority (0=highest, 4=lowest)")
	cmd.Flags().String("labels", "", "Comma-separated labels")
	cmd.Flags().String("acceptance", "", "Acceptance criteria")
	cmd.Flags().String("description", "", "Description")
	cmd.Flags().String("parent", "", "Parent bead ID")
	cmd.Flags().StringArray("set", nil, "Set custom field (key=value, repeatable)")

	return cmd
}

func (f *CommandFactory) newBeadShowCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "show <id>",
		Short: "Show a bead",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			s := f.beadStore()
			b, err := s.GetWithArchive(args[0])
			if err != nil {
				return err
			}

			asJSON, _ := cmd.Flags().GetBool("json")
			if asJSON {
				// Externalized events live in a sidecar; inline them for the
				// JSON view so consumers (and the `events` UI projection)
				// see a single uniform shape.
				if err := s.LoadEventsInline(b); err != nil {
					return err
				}
				data, err := bead.MarshalBead(*b)
				if err != nil {
					return err
				}
				var obj map[string]any
				if err := json.Unmarshal(data, &obj); err != nil {
					return err
				}
				workspaceRoot := f.beadWorkspaceRoot()
				if workspaceRoot == "" {
					workspaceRoot = f.WorkingDir
				}
				metrics, err := beadMetricsFor(workspaceRoot, b.ID)
				if err != nil {
					return err
				}
				if metrics == nil {
					metrics = &beadMetricsSummary{}
				}
				obj["metrics"] = metrics
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(obj)
			}

			out := cmd.OutOrStdout()
			fmt.Fprintf(out, "ID:       %s\n", b.ID)
			fmt.Fprintf(out, "Title:    %s\n", b.Title)
			fmt.Fprintf(out, "Type:     %s\n", b.IssueType)
			fmt.Fprintf(out, "Status:   %s\n", b.Status)
			fmt.Fprintf(out, "Priority: %d\n", b.Priority)
			if len(b.Labels) > 0 {
				fmt.Fprintf(out, "Labels:   %s\n", strings.Join(b.Labels, ", "))
			}
			if b.Owner != "" {
				fmt.Fprintf(out, "Owner:    %s\n", b.Owner)
			}
			if b.Parent != "" {
				fmt.Fprintf(out, "Parent:   %s\n", b.Parent)
			}
			if len(b.Dependencies) > 0 {
				fmt.Fprintf(out, "Deps:     %s\n", strings.Join(b.DepIDs(), ", "))
			}
			if b.Description != "" {
				fmt.Fprintf(out, "Desc:     %s\n", b.Description)
			}
			if b.Acceptance != "" {
				fmt.Fprintf(out, "Accept:   %s\n", b.Acceptance)
			}
			fmt.Fprintf(out, "Created:  %s\n", b.CreatedAt.Format("2006-01-02 15:04:05"))
			fmt.Fprintf(out, "Updated:  %s\n", b.UpdatedAt.Format("2006-01-02 15:04:05"))
			// Show agent session evidence if present
			if b.Extra != nil {
				if sessionID, ok := b.Extra["session_id"]; ok && sessionID != "" {
					fmt.Fprintf(out, "Session:  %v\n", sessionID)
					// Try to resolve session details
					if sess := f.resolveAgentSession(fmt.Sprint(sessionID)); sess != nil {
						fmt.Fprintf(out, "Harness:  %s\n", sess.Harness)
						if sess.Model != "" {
							fmt.Fprintf(out, "Model:    %s\n", sess.Model)
						}
						if sess.Tokens > 0 {
							fmt.Fprintf(out, "Tokens:   %d (in: %d, out: %d)\n", sess.Tokens, sess.InputTokens, sess.OutputTokens)
						}
						if sess.CostUSD > 0 {
							fmt.Fprintf(out, "Cost:     $%.4f\n", sess.CostUSD)
						}
						if sess.Duration > 0 {
							fmt.Fprintf(out, "Duration: %dms\n", sess.Duration)
						}
					}
				}
				if commitSHA, ok := b.Extra["closing_commit_sha"]; ok && commitSHA != "" {
					fmt.Fprintf(out, "Commit:   %v\n", commitSHA)
				}
				if v, ok := b.Extra["claimed-at"]; ok {
					fmt.Fprintf(out, "Claimed:  %v\n", v)
				}
				if v, ok := b.Extra["claimed-machine"]; ok {
					fmt.Fprintf(out, "Machine:  %v\n", v)
				}
				if v, ok := b.Extra["claimed-session"]; ok {
					fmt.Fprintf(out, "Session:  %v\n", v)
				}
				if v, ok := b.Extra["claimed-worktree"]; ok {
					fmt.Fprintf(out, "Worktree: %v\n", v)
				}
			}
			claimKeys := map[string]bool{
				"claimed-at": true, "claimed-pid": true,
				"claimed-machine": true, "claimed-session": true, "claimed-worktree": true,
				"session_id": true, "closing_commit_sha": true,
			}
			for k, v := range b.Extra {
				if !claimKeys[k] {
					fmt.Fprintf(out, "%s: %v\n", k, v)
				}
			}
			return nil
		},
	}
	cmd.Flags().Bool("json", false, "Output as JSON")
	return cmd
}

func (f *CommandFactory) newBeadUpdateCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "update <id>",
		Short: "Update a bead",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			s := f.beadStore()

			// --claim and --unclaim use dedicated store methods
			if claim, _ := cmd.Flags().GetBool("claim"); claim {
				assignee, _ := cmd.Flags().GetString("assignee")
				if assignee == "" {
					assignee = resolveClaimAssignee()
				}
				if err := s.Claim(args[0], assignee); err != nil {
					return err
				}
				f.beadAutoCommit("claim " + args[0])
				return nil
			}
			if unclaim, _ := cmd.Flags().GetBool("unclaim"); unclaim {
				if err := s.Unclaim(args[0]); err != nil {
					return err
				}
				f.beadAutoCommit("unclaim " + args[0])
				return nil
			}

			if unsetFlags, _ := cmd.Flags().GetStringArray("unset"); len(unsetFlags) > 0 {
				for _, key := range unsetFlags {
					if isProtectedBeadExtraKey(key) {
						return fmt.Errorf("cannot unset protected bead field: %s", key)
					}
				}
			}

			var setFlags []string
			if rawSetFlags, _ := cmd.Flags().GetStringArray("set"); len(rawSetFlags) > 0 {
				setFlags = make([]string, 0, len(rawSetFlags))
				for _, kv := range rawSetFlags {
					k, v, ok := strings.Cut(kv, "=")
					if !ok {
						return fmt.Errorf("--set requires key=value format, got: %s", kv)
					}
					if k == "closing_commit_sha" {
						normalizedCommitSHA, err := f.resolveClosingCommitSHA(v)
						if err != nil {
							return err
						}
						v = normalizedCommitSHA
					}
					setFlags = append(setFlags, k+"="+v)
				}
			}

			if err := s.Update(args[0], func(b *bead.Bead) {
				if v, _ := cmd.Flags().GetString("title"); cmd.Flags().Changed("title") {
					b.Title = v
				}
				if v, _ := cmd.Flags().GetString("status"); cmd.Flags().Changed("status") {
					b.Status = v
				}
				if v, _ := cmd.Flags().GetInt("priority"); cmd.Flags().Changed("priority") {
					b.Priority = v
				}
				if v, _ := cmd.Flags().GetString("labels"); cmd.Flags().Changed("labels") {
					if v == "" {
						b.Labels = []string{}
					} else {
						b.Labels = strings.Split(v, ",")
					}
				}
				if v, _ := cmd.Flags().GetString("acceptance"); cmd.Flags().Changed("acceptance") {
					b.Acceptance = v
				}
				if v, _ := cmd.Flags().GetString("assignee"); cmd.Flags().Changed("assignee") {
					b.Owner = v
				}
				if v, _ := cmd.Flags().GetString("parent"); cmd.Flags().Changed("parent") {
					b.Parent = v
				}
				if v, _ := cmd.Flags().GetString("description"); cmd.Flags().Changed("description") {
					b.Description = v
				}
				if v, _ := cmd.Flags().GetString("notes"); cmd.Flags().Changed("notes") {
					b.Notes = v
				}
				if len(setFlags) > 0 {
					if b.Extra == nil {
						b.Extra = make(map[string]any)
					}
					for _, kv := range setFlags {
						k, v, ok := strings.Cut(kv, "=")
						if !ok {
							continue
						}
						// Route known field names to struct fields
						switch k {
						case "parent":
							b.Parent = v
						case "description":
							b.Description = v
						case "notes":
							b.Notes = v
						case "acceptance":
							b.Acceptance = v
						case "issue_type":
							b.IssueType = v
						default:
							// Parse booleans and numbers for proper typing
							switch v {
							case "true":
								b.Extra[k] = true
							case "false":
								b.Extra[k] = false
							default:
								b.Extra[k] = v
							}
						}
					}
				}
				if unsetFlags, _ := cmd.Flags().GetStringArray("unset"); len(unsetFlags) > 0 {
					for _, key := range unsetFlags {
						if b.Extra != nil {
							delete(b.Extra, key)
						}
					}
				}
			}); err != nil {
				return err
			}
			f.beadAutoCommit("update " + args[0])
			return nil
		},
	}

	cmd.Flags().String("title", "", "New title")
	cmd.Flags().String("status", "", "New status (open, in_progress, closed)")
	cmd.Flags().Int("priority", 0, "New priority")
	cmd.Flags().String("labels", "", "New labels (comma-separated)")
	cmd.Flags().String("acceptance", "", "New acceptance criteria")
	cmd.Flags().String("assignee", "", "New assignee or claim assignee fallback")
	cmd.Flags().String("parent", "", "New parent bead ID")
	cmd.Flags().String("description", "", "New description")
	cmd.Flags().String("notes", "", "New notes")
	cmd.Flags().Bool("claim", false, "Claim: set status=in_progress, assignee=ddx")
	cmd.Flags().Bool("unclaim", false, "Unclaim: set status=open, clear assignee and claim fields")
	cmd.Flags().StringArray("set", nil, "Set custom field (key=value, repeatable)")
	cmd.Flags().StringArray("unset", nil, "Unset custom field (key repeatable)")

	return cmd
}

func resolveClaimAssignee() string {
	for _, key := range []string{"DDX_AGENT_NAME", "USER", "LOGNAME", "USERNAME", "SUDO_USER"} {
		if v := os.Getenv(key); v != "" {
			return v
		}
	}
	return "ddx"
}

func isProtectedBeadExtraKey(key string) bool {
	switch key {
	case "events", "session_id", "claimed-at", "claimed-pid", "claimed-machine", "claimed-session", "claimed-worktree":
		return true
	default:
		return false
	}
}

