66					}
67				}
68				f.beadAutoCommit("queue move " + args[0])
69				return nil
70			},
71		}
72		cmd.Flags().String("before", "", "Place the bead before another bead in the same priority bucket")
73		cmd.Flags().String("after", "", "Place the bead after another bead in the same priority bucket")
74		return cmd
75	}
